        function checkPassword() {
            const password = passwordInput.value;
            const rule = levelRules[gameState.currentLevel - 1];

            if (rule.check(password)) {
                statusMessage.textContent = "Correct! Level completed!";
                statusMessage.className = "status-message success";

                // Add level up animation
                document.querySelector('.level-display').classList.add('level-up');
                setTimeout(() => {
                    document.querySelector('.level-display').classList.remove('level-up');
                }, 1000);

                // Move to next level
                if (gameState.currentLevel < gameState.totalLevels) {
                    gameState.currentLevel++;

                    // Check for milestone
                    if (gameState.levelMilestones.includes(gameState.currentLevel)) {
                        showMilestone();
                    }

                    // Unlock new feature
                    if (gameState.currentLevel <= 10) {
                        gameState.features.push(features[gameState.currentLevel - 1]);
                    } else if (gameState.currentLevel <= 20) {
                        gameState.features.push(features[Math.floor(Math.random() * 5)]);
                    } else {
                        gameState.features.push(features[Math.floor(Math.random() * 10)]);
                    }

                    setTimeout(updateUI, 1000);
                } else {
                    // Game completed
                    statusMessage.textContent = "Congratulations! You've completed all levels!";
                    statusMessage.className = "status-message success";
                    checkButton.disabled = true;
                }
            } else {
                statusMessage.textContent = "Incorrect. Try again!";
                statusMessage.className = "status-message error";
            }
        }

        // Show milestone message
        function showMilestone() {
            milestoneMessage.classList.remove('hidden');
            setTimeout(() => {
                milestoneMessage.classList.add('hidden');
            }, 3000);
        }

        // Setup event listeners
        function setupEventListeners() {
            checkButton.addEventListener('click', checkPassword);

            // Allow Enter key to submit
            passwordInput.addEventListener('keyup', (e) => {
                if (e.key === 'Enter') {
                    checkPassword();
                }
            });
        }

        // Initialize the game when page loads
        window.onload = initGame;
