const puppeteer = require('puppeteer');
const fs = require('fs').promises;

class WebCrawler {
  constructor() {
    this.browser = null;
    this.page = null;
  }

  async init() {
    try {
      console.log('Starting browser...');
      this.browser = await puppeteer.launch({
        headless: false, // Set to true for production
        slowMo: 50,
        args: ['--no-sandbox', '--disable-setuid-sandbox']
      });
      this.page = await this.browser.newPage();

      // Set user agent to avoid being blocked
      await this.page.setUserAgent('Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/91.0.4472.124 Safari/537.36');

      console.log('Browser started successfully');
    } catch (error) {
      console.error('Error initializing browser:', error);
      throw error;
    }
  }

  async crawlUrl(url, maxDepth = 2, currentDepth = 0) {
    if (currentDepth > maxDepth) {
      return { urls: [], emails: [] };
    }

    try {
      console.log(`Crawling: ${url} (depth: ${currentDepth})`);

      // Navigate to the page
      await this.page.goto(url, { 
        waitUntil: 'networkidle2',
        timeout: 30000
      });

      // Extract data from the current page
      const results = await this.extractData(url);

      // Get all links from the current page
      const links = await this.page.evaluate(() => {
        const anchors = document.querySelectorAll('a[href]');
        return Array.from(anchors).map(anchor => anchor.href);
      });

      // Filter out only valid URLs
      const validLinks = links.filter(link => 
        link && 
        (link.startsWith('http://') || link.startsWith('https://')) &&
        !link.includes('javascript:') &&
        !link.includes('mailto:')
      );

      console.log(`Found ${validLinks.length} links on ${url}`);

      // Crawl linked pages (up to maxDepth)
      const crawledUrls = [];
      const crawledEmails = new Set();

      for (let i = 0; i < Math.min(validLinks.length, 5); i++) { // Limit to 5 links for demo
        try {
          const link = validLinks[i];
          const subResults = await this.crawlUrl(link, maxDepth, currentDepth + 1);

          // Collect unique emails
          subResults.emails.forEach(email => crawledEmails.add(email));

          // Add URLs from sub-crawls
          crawledUrls.push(...subResults.urls);
        } catch (error) {
          console.warn(`Failed to crawl ${validLinks[i]}:`, error.message);
        }
      }

      // Merge results
      results.urls = [...new Set([...results.urls, ...crawledUrls])]; // Remove duplicates
      results.emails = Array.from(crawledEmails);

      return results;
    } catch (error) {
      console.error(`Error crawling ${url}:`, error);
      return { urls: [], emails: [] };
    }
  }

  async extractData(url) {
    try {
      // Wait for content to load
      await this.page.waitForTimeout(1000);

      // Extract text content
      const content = await this.page.evaluate(() => {
        return {
          title: document.title,
          text: document.body.innerText,
          metaDescription: document.querySelector('meta[name="description"]')?.getAttribute('content') || '',
          h1: Array.from(document.querySelectorAll('h1')).map(h => h.textContent.trim()),
          h2: Array.from(document.querySelectorAll('h2')).map(h => h.textContent.trim())
        };
      });

      // Extract emails using regex
      const emailRegex = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g;
      const emails = content.text.match(emailRegex) || [];

      // Extract URLs from the page
      const urls = await this.page.evaluate(() => {
        const anchors = document.querySelectorAll('a[href]');
        return Array.from(anchors).map(anchor => {
          const href = anchor.href;
          return href && (href.startsWith('http://') || href.startsWith('https://')) ? href : null;
        }).filter(href => href !== null);
      });

      return {
        url: url,
        title: content.title,
        description: content.metaDescription,
        h1Headers: content.h1,
        h2Headers: content.h2,
        urls: urls,
        emails: emails
      };
    } catch (error) {
      console.error('Error extracting data:', error);
      return {
        url: url,
        title: 'Unknown',
        description: 'Failed to extract description',
        h1Headers: [],
        h2Headers: [],
        urls: [],
        emails: []
      };
    }
  }

  async saveResults(results, filename = 'crawl-results.json') {
    try {
      const output = {
        timestamp: new Date().toISOString(),
        results: results
      };

      await fs.writeFile(filename, JSON.stringify(output, null, 2));
      console.log(`Results saved to ${filename}`);
    } catch (error) {
      console.error('Error saving results:', error);
    }
  }

  async close() {
    if (this.browser) {
      await this.browser.close();
      console.log('Browser closed');
    }
  }
}

